// Инлайн функции
function splitFIO(fullName) {
  const parts = (fullName || "").trim().split(/\s+/);
  return {
    surname: parts[0] || "",
    name: parts[1] || "",
    patronymic: parts.slice(2).join(" ") || ""
  };
}

// Функция парсинга регистрационных номеров из реестра
function parseRegNumbers(regNumberString) {
  if (!regNumberString || regNumberString.trim() === "") {
    return {};
  }

  const pairs = regNumberString.split(',').map(s => s.trim());
  const result = {};

  pairs.forEach(pair => {
    const [variable, value] = pair.split(':').map(s => s.trim());
    if (variable && value) {
      result[`<<${variable}>>`] = value;
    }
  });

  return result;
}

function calculateStudyPeriod(regData) {
  const C = config.COLUMNS.REGISTRY;

  // =============================================
  // ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ ДЛЯ РАБОТЫ С ДАТАМИ
  // =============================================

  function isValidDate(date) {
    return date instanceof Date && !isNaN(date.getTime());
  }

  function parseDate(dateValue) {
    if (!dateValue) return null;

    // Обработка формата DD.MM.YYYY (русский формат)
    if (typeof dateValue === 'string') {
      const ddmmyyyyPattern = /^(\d{2})\.(\d{2})\.(\d{4})$/;
      const match = dateValue.match(ddmmyyyyPattern);

      if (match) {
        const [, day, month, year] = match;
        const date = new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
        return isValidDate(date) ? date : null;
      }
    }

    // Для других форматов (ISO, timestamp, объекты Date)
    const date = new Date(dateValue);
    return isValidDate(date) ? date : null;
  }

  function isWeekend(date) {
    const day = date.getDay();
    return day === 0;
    //return day === 0 || day === 6;
  }

  function isHoliday(date) {
    const dateStr = date.toISOString().split('T')[0];
    return config.HOLIDAYS.includes(dateStr);
  }

  function isWorkingDay(date) {
    return !isWeekend(date) && !isHoliday(date);
  }

  function subtractWorkingDays(endDate, daysToSubtract) {
    let currentDate = new Date(endDate);
    let workingDaysCount = 0;

    // Включаем конечную дату в подсчёт
    if (isWorkingDay(currentDate)) {
      workingDaysCount = 1;
    }

    // Вычитаем оставшиеся дни
    while (workingDaysCount < daysToSubtract) {
      currentDate.setDate(currentDate.getDate() - 1);
      if (isWorkingDay(currentDate)) {
        workingDaysCount++;
      }
    }

    return currentDate;
  }

  function formatDateRussian(date) {
    const d = new Date(date);
    const day = String(d.getDate()).padStart(2, '0');
    const month = config.MONTH_NAMES.genitive[d.getMonth()];
    const year = d.getFullYear();
    return `«${day}» ${month} ${year} года`;
  }

  function formatShortRussian(date) {
    const d = new Date(date);
    const day = String(d.getDate()).padStart(2, '0');
    const month = config.MONTH_NAMES.genitive[d.getMonth()];
    return `«${day}» ${month}`;
  }

  function formatDateDDMMYYYY(date) {
    const d = new Date(date);
    return `${String(d.getDate()).padStart(2,"0")}.${String(d.getMonth()+1).padStart(2,"0")}.${d.getFullYear()}`;
  }

  function getDefaultPeriod() {
    const endDate = new Date();
    const startDate = new Date();
    startDate.setDate(endDate.getDate() - 30);
    return formatPeriodResult(startDate, endDate);
  }

  function formatPeriodResult(startDate, endDate) {
    return {
      startDate,
      endDate,
      startDay: String(startDate.getDate()).padStart(2, '0'),
      startMonth: config.MONTH_NAMES.genitive[startDate.getMonth()],
      startYear: startDate.getFullYear(),
      endDay: String(endDate.getDate()).padStart(2, '0'),
      endMonth: config.MONTH_NAMES.genitive[endDate.getMonth()],
      endYear: endDate.getFullYear(),
      startDateFormatted: formatDateRussian(startDate),
      endDateFormatted: formatDateRussian(endDate),
      shortEnd: formatShortRussian(endDate),
      dateFull: formatDateDDMMYYYY(endDate),
      startDateFull: formatDateDDMMYYYY(startDate),
      periodRange: `${formatDateDDMMYYYY(startDate)} - ${formatDateDDMMYYYY(endDate)}`
    };
  }

  // =============================================
  // ЛОГИКА ОПРЕДЕЛЕНИЯ ПЕРИОДА (5 ВАРИАНТОВ)
  // =============================================

  // Парсим все возможные даты заранее
  const startDateValue = parseDate(regData[C.START_DATE]);
  const endDateValue = parseDate(regData[C.END_DATE]);
  const issueDateValue = parseDate(regData[C.ISSUE_DATE]);
  const createdDateValue = parseDate(regData[C.CUSTOM_DATE]) || parseDate(regData[C.CREATED_DATE]);
  const customTerm = regData[C.CUSTOM_TERM] ? parseInt(regData[C.CUSTOM_TERM]) : null;
  const hours = regData[C.HOURS] ? parseInt(regData[C.HOURS]) : null;

  // 1️⃣ ВАРИАНТ 1: START_DATE + END_DATE
  if (startDateValue && endDateValue) {
    console.log("Вариант 1: Используем фиксированные START_DATE и END_DATE");
    return formatPeriodResult(startDateValue, endDateValue);
  }

  // 2️⃣ ВАРИАНТ 2: ISSUE_DATE + CUSTOM_TERM
  if (issueDateValue && customTerm && !isNaN(customTerm)) {
    console.log("Вариант 2: Используем ISSUE_DATE + CUSTOM_TERM");
    const endDate = issueDateValue;
    const startDate = subtractWorkingDays(endDate, customTerm);
    return formatPeriodResult(startDate, endDate);
  }

  // 3️⃣ ВАРИАНТ 3: Только ISSUE_DATE (+ часы для расчета)
  if (issueDateValue && hours && !isNaN(hours)) {
    console.log("Вариант 3: Используем только ISSUE_DATE (+ часы для расчета периода)");
    const period = config.HOURS_TO_PERIOD[String(hours)];

    if (!period) {
      console.warn(`Неизвестное количество часов: ${hours}`);
      return getDefaultPeriod();
    }

    const endDate = issueDateValue;
    const startDate = subtractWorkingDays(endDate, period.value);
    return formatPeriodResult(startDate, endDate);
  }

  // 4️⃣ ВАРИАНТ 4: Только CUSTOM_TERM + CREATED_DATE
  if (customTerm && !isNaN(customTerm) && createdDateValue) {
    console.log("Вариант 4: Используем только CUSTOM_TERM + CREATED_DATE");
    const endDate = createdDateValue;
    const startDate = subtractWorkingDays(endDate, customTerm);
    return formatPeriodResult(startDate, endDate);
  }

  // 5️⃣ ВАРИАНТ 5: Только CREATED_DATE (+ часы для расчета)
  if (createdDateValue && hours && !isNaN(hours)) {
    console.log("Вариант 5: Используем только CREATED_DATE (+ часы для расчета периода)");
    const period = config.HOURS_TO_PERIOD[String(hours)];

    if (!period) {
      console.warn(`Неизвестное количество часов: ${hours}`);
      return getDefaultPeriod();
    }

    const endDate = createdDateValue;
    const startDate = subtractWorkingDays(endDate, period.value);
    return formatPeriodResult(startDate, endDate);
  }

  // 🔄 FALLBACK: Если ничего не подошло
  console.warn("Не найдены необходимые данные для расчета периода, используем default");
  return getDefaultPeriod();
}

