// Функция генерации регистрационного номера
function generateRegNumber(documentType, counters) {
  const baseDocForFormat = documentType;
  const format = config.REG_NUMBER_FORMATS[baseDocForFormat];
  if (!format) return { regNumber: "", counterUpdate: null };

  if (format.useParent) return { regNumber: "", counterUpdate: null };

  const counter = counters.find(c => 
    c.json[config.COLUMNS.COUNTERS.COUNTER_TYPE] === format.counter_name
  );

  let currentValue = counter ? 
    parseInt(counter.json[config.COLUMNS.COUNTERS.CURRENT_VALUE]) : 
    format.startFrom;

  currentValue += 1;

  const now = new Date();
  const month = String(now.getMonth() + 1).padStart(2, "0");
  const year = String(now.getFullYear());
  const yy = year.slice(-2);

  let regNumber = format.format
    .replace("{number}", currentValue)
    .replace("{month}", month)
    .replace("{yy}", yy)
    .replace("{prefix}", format.prefix);

  return { 
    regNumber, 
    counterUpdate: { 
      name: format.counter_name, 
      value: currentValue 
    }
  };
}

