  if (regVariable && regNumber && isNewDocument) {
      variables[`<<${regVariable}>>`] = regNumber;
      console.log(`    - добавлена переменная регномера: <<${regVariable}>> = ${regNumber}`);
    }
      // Определяем существующий документ
    const existingDocument = hasExistingDocuments ? folderLink : null;

    // Формируем имя файла
    const firstName = fullName.split(' ')[0];
    const targetName = documentType.includes("<<Профессия>>")? `${id}_${firstName}_ДНЕВНИК_ПРАКТИКИ_${reg[C.PROGRAM]}_${documentType.split(' ')[1]}`:`${id}_${firstName}_${documentType}`;

    tasks.push({
      json: {
        id,
        employee,
        scenario,
        documentType,
        templateId: template[config.COLUMNS.TEMPLATES.TEMPLATE_LINK],
        variables,
        regNumber,
        targetName,
        existingDocument,
        action: existingDocument ? "update_document" : "create_document"
      }
    });
  };

  // Генерируем документы согласно сценари
    documentsToGenerate.forEach(documentType => {
    // Определяем, является ли документ подложкой по названию
    createTask(documentType);
  });
});

// Добавляем задачу обновления счетчиков
if (counterUpdates.size > 0) {
  tasks.push({
    json: {
      action: "update_counters",
      counters: Array.from(counterUpdates.entries()).map(([name, value]) => ({
        name,
        value
      }))
    }
  });
}

console.log(`\n=== ИТОГО ===`);
console.log(`Подготовлено задач: ${tasks.length}`);
console.log(`- Создать документов: ${tasks.filter(t => t.json.action === "create_document").length}`);
console.log(`- Обновить документов: ${tasks.filter(t => t.json.action === "update_document").length}`);
console.log(`- Ошибок: ${tasks.filter(t => t.json.action === "error").length}`);
console.log(`- Обновить счетчиков: ${counterUpdates.size}`);

// ===============================================
//     ГРУППИРОВКА ПО ЗАЯВКАМ
// ===============================================

// Отделяем служебные задачи
const serviceTasks = tasks.filter(task => {
  const data = task.json;
  return data.action === "update_counters" || data.action === "error";
});

// Получаем только задачи создания/обновления документов
const documentTasks = tasks.filter(task => {
  const data = task.json;
  return data.action === "create_document" || data.action === "update_document";
});

console.log(`\nГруппировка: ${documentTasks.length} документов, ${serviceTasks.length} служебных`);

// Группируем по ID заявки
const requestGroups = new Map();

documentTasks.forEach(task => {
  const data = task.json;
  const requestId = data.id;

  if (!requestGroups.has(requestId)) {
    requestGroups.set(requestId, {
      id: requestId,
      employee: data.employee,
      scenario: data.scenario,
      fullName: `${data.variables["<<Фамилия>>"]} ${data.variables["<<Имя>>"]} ${data.variables["<<Отчество>>"]}`,
      regNumber: data.regNumber,
      existingDocument: data.existingDocument,
      documents: [],
      totalDocuments: 0,
      createdCount: 0,
      updatedCount: 0
    });
  }

  const group = requestGroups.get(requestId);

  // Добавляем документ в группу
  group.documents.push({
    documentType: data.documentType,
    templateId: data.templateId,
    variables: data.variables,
    targetName: data.targetName,
    existingDocument: data.existingDocument,
    action: data.action
  });

  // Увеличиваем счетчики
  group.totalDocuments++;
  if (data.action === "create_document") {
    group.createdCount++;
  } else if (data.action === "update_document") {
    group.updatedCount++;
  }
});

// Преобразуем группы в массив пакетов
const requestPackets = Array.from(requestGroups.values()).map(group => ({
  json: {
    requestId: group.id,
    employee: group.employee,
    scenario: group.scenario,
    fullName: group.fullName,
    regNumber: group.regNumber,
    existingDocument: group.existingDocument,

    // Статистика пакета
    summary: {
      totalDocuments: group.totalDocuments,
      toCreate: group.createdCount,
      toUpdate: group.updatedCount
    },

    // Список документов для генерации
    documents: group.documents,

    // Метаданные
    processingType: "batch",
    createdAt: new Date().toISOString()
  }
}));

// Объединяем пакеты и служебные задачи
const result = [...requestPackets, ...serviceTasks];

console.log(`\n=== РЕЗУЛЬТАТ ГРУППИРОВКИ ===`);
console.log(`Пакетов заявок: ${requestPackets.length}`);
requestPackets.forEach(packet => {
  const data = packet.json;
  console.log(`  ${data.requestId}: ${data.summary.totalDocuments} документов (создать: ${data.summary.toCreate}, обновить: ${data.summary.toUpdate})`);
});

return result;

// Функция для извлечения текста из одной ячейки таблицы
function extractCellText(cell) {
  if (!cell || !cell.content) return '';

  let text = '';
  for (const element of cell.content) {
    if (element.paragraph && element.paragraph.elements) {
      for (const paragraphElement of element.paragraph.elements) {
        if (paragraphElement.textRun && paragraphElement.textRun.content) {
          text += paragraphElement.textRun.content;
        }
      }
    }
  }

  return text.trim();
}

// Функция для извлечения данных из одной таблицы (только 1 и 3 столбцы, без первой и последней строки)
function extractTableData(table) {
  if (!table || !table.tableRows) return [];

  const tableData = [];

  for (const row of table.tableRows) {
    const rowData = [];

    if (row.tableCells) {
      // Извлекаем только 1-й (индекс 0) и 3-й (индекс 2) столбцы
      if (row.tableCells[0]) {
        rowData.push(extractCellText(row.tableCells[0]));
      }
      if (row.tableCells[2]) {
        rowData.push(extractCellText(row.tableCells[2]));
      }
    }

    tableData.push(rowData);
  }

  // Убираем первую и последнюю строки
  if (tableData.length > 2) {
    return tableData.slice(1, -1);
  }

  return [];
}

// Функция для обработки одного документа
function processDocument(doc) {
  const tables = [];

  if (!doc.body || !doc.body.content) {
    return tables;
  }

  for (const element of doc.body.content) {
    if (element.table) {
      const tableData = extractTableData(element.table);
      tables.push({
        documentId: doc.documentId || 'unknown',
        documentTitle: doc.title || 'untitled',
        tableIndex: tables.length,
        rowCount: tableData.length,
        columnCount: tableData.length > 0 ? tableData[0].length : 0,
        data: tableData
      });
    }
  }

  return tables;
}

// Основной код для n8n
const inputItems = $input.all();
const outputItems = [];

for (const item of inputItems) {
  const doc = item.json;

  // Обрабатываем документ
  const tables = processDocument(doc);

  // Создаём отдельный выходной элемент для каждой таблицы
  for (const table of tables) {
    outputItems.push({
      json: {
        documentId: table.documentId,
        documentTitle: table.documentTitle,
        tableIndex: table.tableIndex,
        rowCount: table.rowCount,
        columnCount: table.columnCount,
        tableData: table.data
      }
    });
  }
}

return outputItems;

const inputItems = $input.all();
const outputItems = [];
const itemsDates = $('isDiary').all()

// Функция для форматирования даты в формат ДД.ММ.ГГГГ
function formatDate(date) {
  const day = String(date.getDate()).padStart(2, '0');
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const year = date.getFullYear();
  return `${day}.${month}.${year}`;
}

// Функция для парсинга даты из формата ДД.ММ.ГГГГ
function parseDate(dateStr) {
  const [day, month, year] = dateStr.split('.');
  return new Date(year, month - 1, day);
}

let dateIndex = 0;
for (const item of inputItems) {
  // Получаем входную дату 
  const inputDateStr = itemsDates[dateIndex].json.variables['<<Дата>>'];//item.json.inputDate; // например "13.10.2025"
  const inputDate = parseDate(inputDateStr);
  dateIndex++
  console.log(inputDateStr)
  // Финиш = входная дата - 1 день
  const finishDate = new Date(inputDate);
  finishDate.setDate(finishDate.getDate() - 1);

  // Обрабатываем tableData
  const tableData = item.json.tableData;
  const replacements = [];

  let currentDate = new Date(finishDate);

  // Проходим снизу вверх (от финиша к старту)
  for (let i = tableData.length - 1; i >= 0; i--) {
    const row = tableData[i];
    const hours = parseFloat(row[1]);
    const days = Math.ceil(hours / 8); // округляем вверх (до 8 часов = 1 день)

    // Определяем переменную
    let variable;
    if (i === tableData.length - 1) {
      variable = "<<Финиш>>";
    } else if (i === 0) {
      variable = "<<Старт>>";
    } else {
      // Номер от 2 до (length - 1), идёт от старта к финишу
      const position = i + 1;
      variable = `<<дата-${position}>>`;
    }

    // Формируем дату/диапазон с переносами строк
    let dateRange;
    if (days === 1) {
      dateRange = formatDate(currentDate);
    } else {
      const startDate = new Date(currentDate);
      startDate.setDate(startDate.getDate() - (days - 1));
      dateRange = `${formatDate(startDate)}\n-\n${formatDate(currentDate)}`;
    }

    // Добавляем замену для Google Docs API
    replacements.unshift({
      replaceAllText: {
        containsText: {
          text: variable,
          matchCase: true
        },
        replaceText: dateRange
      }
    });

    // Переходим к следующей (более ранней) дате
    if (i > 0) {
      currentDate.setDate(currentDate.getDate() - days);
    }
  }

  // Формируем готовый JSON для API запроса
  outputItems.push({
    json: {
      documentId: item.json.documentId,
      documentTitle: item.json.documentTitle,
      inputDate: inputDateStr,
      apiRequest: {
        requests: replacements
      }
    }
  });
}

return outputItems;

