console.log(`- Ошибок: ${tasks.filter(t => t.json.action === "error").length}`);
console.log(`- Обновить счетчиков: ${counterUpdates.size}`);

// ===============================================
//     ГРУППИРОВКА ПО ЗАЯВКАМ
// ===============================================

// Отделяем служебные задачи
const serviceTasks = tasks.filter(task => {
  const data = task.json;
  return data.action === "update_counters" || data.action === "error";
});

// Получаем только задачи создания/обновления документов
const documentTasks = tasks.filter(task => {
  const data = task.json;
  return data.action === "create_document" || data.action === "update_document";
});

console.log(`\nГруппировка: ${documentTasks.length} документов, ${serviceTasks.length} служебных`);

// Группируем по ID заявки
const requestGroups = new Map();

documentTasks.forEach(task => {
  const data = task.json;
  const requestId = data.id;

  if (!requestGroups.has(requestId)) {
    requestGroups.set(requestId, {
      id: requestId,
      employee: data.employee,
      scenario: data.scenario,
      fullName: `${data.variables["<<Фамилия>>"]} ${data.variables["<<Имя>>"]} ${data.variables["<<Отчество>>"]}`,
      regNumber: data.regNumber,
      existingDocument: data.existingDocument,
      documents: [],
      totalDocuments: 0,
      createdCount: 0,
      updatedCount: 0
    });
  }

  const group = requestGroups.get(requestId);

  // Добавляем документ в группу
  group.documents.push({
    documentType: data.documentType,
    templateId: data.templateId,
    templateType: data.templateType,
    folderType: data.folderType,
    underlay: data.underlay,
    variables: data.variables,
    targetName: data.targetName,
    existingDocument: data.existingDocument,
    action: data.action
  });

  // Увеличиваем счетчики
  group.totalDocuments++;
  if (data.action === "create_document") {
    group.createdCount++;
  } else if (data.action === "update_document") {
    group.updatedCount++;
  }
});

// Преобразуем группы в массив пакетов
const requestPackets = Array.from(requestGroups.values()).map(group => ({
  json: {
    requestId: group.id,
    employee: group.employee,
    scenario: group.scenario,
    fullName: group.fullName,
    regNumber: group.regNumber,
    existingDocument: group.existingDocument,

    // Статистика пакета
    summary: {
      totalDocuments: group.totalDocuments,
      toCreate: group.createdCount,
      toUpdate: group.updatedCount
    },

    // Список документов для генерации
    documents: group.documents,

    // Метаданные
    processingType: "batch",
    createdAt: new Date().toISOString()
  }
}));

// Объединяем пакеты и служебные задачи
const result = [...requestPackets, ...serviceTasks];

console.log(`\n=== РЕЗУЛЬТАТ ГРУППИРОВКИ ===`);
console.log(`Пакетов заявок: ${requestPackets.length}`);
requestPackets.forEach(packet => {
  const data = packet.json;
  console.log(`  ${data.requestId}: ${data.summary.totalDocuments} документов (создать: ${data.summary.toCreate}, обновить: ${data.summary.toUpdate})`);
});

return result;

