parameters.jsCode:
const input = $('regen_or_new').all().map(item => item.json);

const allDocuments = input.flatMap(req =>
  (req.documents || []).map(doc => ({
    ...doc,
    requestId: req.requestId
  }))
);

return allDocuments.map(doc => ({ json: doc }));

// Получаем данные из предыдущей ноды
const foldersData = $('CreateStudentFolder1').all();
// Создаем один объект со всеми REQ-номерами
const result = {};

foldersData.forEach(item => {
  const data = item.json;

  result[data.name.split('_')[2]] = {
    id: data.id
  };
});

return [result];

