parameters.jsCode:
// ===============================================
//     НОДА: ОДИН ITEM НА ОДНУ СТРОКУ
// ===============================================

// Получаем конфигурацию из предыдущей ноды
const config = $('config').first().json.config;
const request_counter = $('GetRequestCounter').first().json['Текущее значение']
let currentCounter = request_counter;

const existing_ids = $('GetLayoutsIDExisting').all().map(item => item.json.ID)

// Получаем данные из Google Sheets (лист "Реестр заявок")  
const registryData = $('checkTable').all();

// 👇 Получаем базу профессий и фильтруем только строки с данными
const professionDatabase = $('GetProfessionDatabase').all().filter(item => {
  const profession = item.json[config.COLUMNS.PROFESSION_DATABASE.PROFESSION_NAME];
  return profession && String(profession).trim() !== '';
});

function getRowNumber(rowObj, idx) {
  return rowObj.row_number || rowObj._rowNumber || rowObj.rowNumber || (idx + 2);
}

// 👇 ФУНКЦИЯ: Поиск профессии в базе
function findProfession(programName) {
  if (!programName || String(programName).trim() === '') {
    return null;
  }

  const program = String(programName).trim();
  const C_PROF = config.COLUMNS.PROFESSION_DATABASE;

  // Ищем совпадение по PROFESSION_NAME из конфига
  const found = professionDatabase.find(item => {
    const profName = item.json[C_PROF.PROFESSION_NAME];
    return profName && String(profName).trim() === program;
  });

  return found ? found.json : null;
}

// 👇 ФУНКЦИЯ: Проверка разряда (ИСПРАВЛЕННАЯ)
function validateWorkClass(workClass, professionData) {
  if (!professionData) {
    return false;
  }

  const C_PROF = config.COLUMNS.PROFESSION_DATABASE;
  const professionClass = professionData[C_PROF.PROFESSION_CLASS];

  // 👇 НОВАЯ ЛОГИКА: Если в базе "-", то разряд должен быть пустым
  if (professionClass === '-' || !professionClass || String(professionClass).trim() === '') {
    // Если разряд НЕ указан в реестре → ✅ ОК
    if (!workClass || String(workClass).trim() === '') {
      return true;  // ✅ Пусто в реестре = нормально
    }
    // Если разряд указан → ❌ ОШИБКА
    return false;  // ❌ В базе нет разрядов, а в реестре указан
  }

  // Если в базе есть разряды, проверяем их
  const workClassNumber = String(workClass).trim().split(' ')[0];
  const allowedClasses = String(professionClass).split(',').map(c => c.trim());

  return allowedClasses.includes(workClassNumber);
}

// Массив результатов - один item на строку
const results = [];

// Обрабатываем каждую строку
registryData.forEach((item, index) => {

  try {
    const row = item.json;
    const rowNumber = getRowNumber(row, index);
    const C = config.COLUMNS;

    // Проверка обязательных полей
    const missing = [];
    for (const field of config.REQUIRED_FIELDS.base) {
      const value = row[field];
      if (value === undefined || value === null || String(value).trim() === '') {
        missing.push(field);
      }
    }

    // Проверка допустимых часов
    const hours = parseInt(row[C.REGISTRY.HOURS]);
    if (!isNaN(hours) && !config.VALID_HOURS.includes(hours)) {
      missing.push(`${C.REGISTRY.HOURS} (недопустимое значение: ${hours})`);
    }

    // 👇 ПРОВЕРКА: Проверка профессии и разряда
    const programName = row[C.REGISTRY.PROGRAM];
    const workClass = row[C.REGISTRY.WORK_CLASS];

    let professionData = null;
    let professionCode = null;

    if (programName && String(programName).trim() !== '') {
      professionData = findProfession(programName);

      if (!professionData) {
        // ❌ Профессия не найдена в базе
        missing.push('Профессия отсутствует в приказе');
      } else {
        // ✅ Профессия найдена
        const C_PROF = config.COLUMNS.PROFESSION_DATABASE;
        professionCode = professionData[C_PROF.PROFESSION_CODE];

        // 👇 НОВАЯ ЛОГИКА: Проверка разряда (ВАРИАНТ Б)
        if (workClass && String(workClass).trim() !== '') {
          // Разряд указан → проверяем корректность
          const isValidClass = validateWorkClass(workClass, professionData);

          if (!isValidClass) {
            missing.push('Неверно указан разряд');
          }
        } else {
          // Разряд НЕ указан → проверяем, обязателен ли он
          const professionClass = professionData[C_PROF.PROFESSION_CLASS];

          // Если в базе есть разряды (не "-" и не пусто), то разряд обязателен
          if (professionClass && 
              professionClass !== '-' && 
              String(professionClass).trim() !== '') {
            missing.push('Не указан разряд (обязателен для этой профессии)');
          }
        }
      }
    }
    if (missing.length === 0) {
      // ✅ Все проверки пройдены
      const existingId = row[C.REGISTRY.ID];

      if (!existingId || String(existingId).trim() === '') {
        // ✅ ID нет → генерируем новый
        let newId;
        do {
          currentCounter += 1;
          newId = `REQ-${String(currentCounter).padStart(5, '0')}`;
        } while (existing_ids.includes(newId));

        const fullName = row[C.REGISTRY.FULL_NAME] || 'Не указано';

        results.push({
          json: {
            rowNumber,
            action: 'assign_id',
            newId,
            fullName,
            professionCode, // 👈 Код профессии (может быть null если не найдено)

            registryUpdates: {
              [C.REGISTRY.LAST_UPDATE]: new Date().toLocaleString('ru-RU', {
                timeZone: 'Europe/Moscow',
                year: 'numeric',
                month: '2-digit', 
                day: '2-digit',
                hour: '2-digit',
                minute: '2-digit'
              })
            }
          }
        });

      } else {
        // ✅ ID уже есть → пропускаем
        const fullName = row[C.FULL_NAME] || 'Не указано';

        results.push({
          json: {
            rowNumber,
            action: 'exist_id',
            existingId,
            fullName,
            professionCode, // 👈 Код профессии (может быть null если не найдено)

            registryUpdates: {
              [C.REGISTRY.LAST_UPDATE]: new Date().toLocaleString('ru-RU', {
                timeZone: 'Europe/Moscow',
                year: 'numeric',
                month: '2-digit', 
                day: '2-digit',
                hour: '2-digit',
                minute: '2-digit'
              })
            }
          }
        });
      }
    } else {
      // ❌ Неполные данные - БЕЗ КОДА ПРОФЕССИИ
      const fullName = row[C.FULL_NAME] || 'Не указано';

      results.push({
        json: {
          rowNumber,
          action: 'incomplete',
          fullName,
          missingFields: missing,
          // 👈 НЕТ professionCode для incomplete!

          registryUpdates: {
            [C.REGISTRY.LAST_UPDATE]: new Date().toLocaleString('ru-RU', {
              timeZone: 'Europe/Moscow',
              year: 'numeric',
              month: '2-digit', 
              day: '2-digit',
              hour: '2-digit',
              minute: '2-digit'
            })
          }
        }
      });
    }

  } catch (err) {
    // Ошибка обработки строки
    results.push({
      json: {
        rowNumber: index + 2,
        action: 'error',
        error: err.message
      }
    });
  }
});

console.log(`Обработано: ${results.length} строк`);
const assigned = results.filter(r => r.json.action === 'assign_id').length;
const incomplete = results.filter(r => r.json.action === 'incomplete').length;
const existId = results.filter(r => r.json.action === 'exist_id').length;

console.log(`- Присвоено ID: ${assigned}`);
console.log(`- Существующий ID: ${existId}`);
console.log(`- Неполные данные: ${incomplete}`);

results.push({
  json: {
    counterUpdate: currentCounter
  }
});

return results;

// ===============================================
//     НОДА: ОДИН ITEM НА ОДНУ СТРОКУ
// ===============================================

// 📦 конфиг
const config = $('config').first().json.config;
const request_counter = $('GetRequestCounter').first().json['Текущее значение'];
let currentCounter = request_counter;

// 🆔 существующие ID
const existing_ids = $('GetLayoutsIDExisting').all().map(item => item.json.ID);

// 👨‍💼 headSource (защита от [{}])
const secondSourceItems = $('GetCheckID')?.all?.() || [];

const headSourceIds = new Set(
  secondSourceItems
    .map(i => i?.json || {})
    .map(r => r.ID)
    .filter(id => typeof id === 'string' && id.trim().length > 0)
);

// 📊 данные таблицы
const registryData = $('checkTable').all();

// ===============================================
// 📅 DATE PARSER
// ===============================================
function parseDateDDMMYYYY(str) {
  if (!str || typeof str !== 'string') return null;

  const parts = str.split('.');
  if (parts.length !== 3) return null;

  const [day, month, year] = parts.map(Number);
  if (!day || !month || !year) return null;

  return new Date(year, month - 1, day);
}

// 🔞 возраст
function isAdult(birthDateStr) {
  const birthDate = parseDateDDMMYYYY(birthDateStr);
  if (!birthDate) return false;

  const today = new Date();

  let age = today.getFullYear() - birthDate.getFullYear();
  const m = today.getMonth() - birthDate.getMonth();

  if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
    age--;
  }

  return age >= 18;
}

// ===============================================
// 🔁 результат
// ===============================================
const results = [];

// ===============================================
// 🔥 ОБРАБОТКА СТРОК
// ===============================================
registryData.forEach((item, index) => {
  try {

    const row = item.json;
    const rowNumber = row.row_number || row._rowNumber || row.rowNumber || (index + 2);
    const C = config.COLUMNS;

    const fullName = row[C.REGISTRY.FULL_NAME] || 'Не указано';

    // ===============================================
    // 🔍 missing fields
    // ===============================================
    const missing = [];

    for (const field of config.REQUIRED_FIELDS.base) {
      const value = row[field];
      if (value === undefined || value === null || String(value).trim() === '') {
        missing.push(field);
      }
    }

    // проверка часов
    const hours = Number(row[C.REGISTRY.HOURS]);
    if (!isNaN(hours) && !config.VALID_HOURS.includes(hours)) {
      missing.push(`${C.REGISTRY.HOURS} (недопустимое значение: ${hours})`);
    }

    // ===============================================
    // 🔞 age check
    // ===============================================
    const birthDateValue = row[C.REGISTRY.BIRTH_DATE];
    const isUnderage = birthDateValue ? !isAdult(birthDateValue) : false;

    // ===============================================
    // 🆔 ID check
    // ===============================================
    const existingId = row[C.REGISTRY.ID];
    const isInHeadSource = existingId && headSourceIds.has(existingId);

    // ===============================================
    // 🔥 1. CHECK_BY_HEAD (ПРИОРИТЕТ)
    // ===============================================
    if (isInHeadSource) {
      results.push({
        json: {
          rowNumber,
          action: 'check_by_head',
          existingId,
          fullName,
          registryUpdates: {
            [C.REGISTRY.LAST_UPDATE]: new Date().toLocaleString('ru-RU', {
              timeZone: 'Europe/Moscow',
              year: 'numeric',
              month: '2-digit',
              day: '2-digit',
              hour: '2-digit',
              minute: '2-digit'
            })
          }
        }
      });
      return;
    }

    // ===============================================
    // 🔞 2. UNDERAGE
    // ===============================================
    if (isUnderage) {
      results.push({
        json: {
          rowNumber,
          action: 'underage',
          fullName,
          birthDate: birthDateValue,
          registryUpdates: {
            [C.REGISTRY.LAST_UPDATE]: new Date().toLocaleString('ru-RU', {
              timeZone: 'Europe/Moscow',
              year: 'numeric',
              month: '2-digit',
              day: '2-digit',
              hour: '2-digit',
              minute: '2-digit'
            })
          }
        }
      });
      return;
    }

    // ===============================================
    // ❌ 3. INCOMPLETE
    // ===============================================
    if (missing.length > 0) {
      results.push({
        json: {
          rowNumber,
          action: 'incomplete',
          fullName,
          missingFields: missing,
          registryUpdates: {
            [C.REGISTRY.LAST_UPDATE]: new Date().toLocaleString('ru-RU', {
              timeZone: 'Europe/Moscow',
              year: 'numeric',
              month: '2-digit',
              day: '2-digit',
              hour: '2-digit',
              minute: '2-digit'
            })
          }
        }
      });
      return;
    }

    // ===============================================
    // 🆔 4. ASSIGN ID
    // ===============================================
    if (!existingId || String(existingId).trim() === '') {

      let newId;
      do {
        currentCounter += 1;
        newId = `REQ-${String(currentCounter).padStart(5, '0')}`;
      } while (existing_ids.includes(newId));

      existing_ids.push(newId);

      results.push({
        json: {
          rowNumber,
          action: 'assign_id',
          newId,
          fullName,
          registryUpdates: {
            [C.REGISTRY.LAST_UPDATE]: new Date().toLocaleString('ru-RU', {
              timeZone: 'Europe/Moscow',
              year: 'numeric',
              month: '2-digit',
              day: '2-digit',
              hour: '2-digit',
              minute: '2-digit'
            })
          }
        }
      });

      return;
    }

    // ===============================================
    // 🔵 5. EXIST_ID
    // ===============================================
    results.push({
      json: {
        rowNumber,
        action: 'exist_id',
        existingId,
        fullName,
        registryUpdates: {
          [C.REGISTRY.LAST_UPDATE]: new Date().toLocaleString('ru-RU', {
            timeZone: 'Europe/Moscow',
            year: 'numeric',
            month: '2-digit',
            day: '2-digit',
            hour: '2-digit',
            minute: '2-digit'
          })
        }
      }
    });

  } catch (err) {
    results.push({
      json: {
        rowNumber: index + 2,
        action: 'error',
        error: err.message
      }
    });
  }
});

// ===============================================
// 📊 LOGS
// ===============================================
console.log(`Обработано: ${results.length} строк`);

console.log(`- assign_id: ${results.filter(r => r.json.action === 'assign_id').length}`);
console.log(`- exist_id: ${results.filter(r => r.json.action === 'exist_id').length}`);
console.log(`- incomplete: ${results.filter(r => r.json.action === 'incomplete').length}`);
console.log(`- underage: ${results.filter(r => r.json.action === 'underage').length}`);
console.log(`- check_by_head: ${results.filter(r => r.json.action === 'check_by_head').length}`);

// ===============================================
// 🔁 counter update
// ===============================================
results.push({
  json: {
    counterUpdate: currentCounter
  }
});

return results;

